document.addEventListener("DOMContentLoaded",()=>{const e=document.getElementById("loader-wrapper"),t=document.getElementById("main-content");if(!t)return void console.error("No element with id 'main-content' found. Please wrap your page content in <div id='main-content'>");if(sessionStorage.getItem("loaderShown"))return e.style.display="none",void(t.style.display="block");sessionStorage.setItem("loaderShown","true"),e.style.display="flex",e.style.opacity="1",t.style.display="none",setTimeout(()=>{e.style.transition="opacity 0.5s ease",e.style.opacity="0",setTimeout(()=>{e.style.display="none",t.style.display="block"},500)},5e3)});